#### 2. WebSocket 连接监控类

```javascript
// 新增 scripts/connection-monitor.js

class ConnectionMonitor {
  constructor(ws) {
    this.ws = ws;
    this.metrics = {
      connectTime: null,
      lastHeartbeat: null,
      messagesSent: 0,
      messagesReceived: 0,
      reconnects: [],
      latencyHistory: [],
      maxHistoryLength: 50
    };

    this.startMonitoring();
  }

  startMonitoring() {
    // 监听消息
    this.ws.onmessage = (event) => {
      this.metrics.messagesReceived++;
      this.updateMessageCount();

      // 检测心跳消息
      const data = JSON.parse(event.data);
      if (data.event === 'heartbeat') {
        this.calculateLatency(data.timestamp);
      }
    };

    // 监听连接状态
    this.ws.onopen = () => {
      this.metrics.connectTime = Date.now();
      this.addReconnectEvent('connected');
      this.startDurationTimer();
      this.startLatencyChart();
    };

    this.ws.onclose = () => {
      this.addReconnectEvent('disconnected');
      this.stopDurationTimer();
    };

    this.ws.onerror = (error) => {
      this.addReconnectEvent('error', error.message);
    };
  }

  calculateLatency(serverTimestamp) {
    const now = Date.now();
    const latency = now - serverTimestamp;

    this.metrics.lastHeartbeat = now;
    this.metrics.latencyHistory.push({
      timestamp: now,
      latency: latency
    });

    // 限制历史长度
    if (this.metrics.latencyHistory.length > this.maxHistoryLength) {
      this.metrics.latencyHistory.shift();
    }

    this.updateLatencyDisplay(latency);
    this.updateLatencyChart();
  }

  addReconnectEvent(status, message = '') {
    const event = {
      timestamp: new Date().toLocaleTimeString(),
      status,
      message
    };

    this.metrics.reconnects.unshift(event);

    // 限制历史记录数量
    if (this.metrics.reconnects.length > 20) {
      this.metrics.reconnects.pop();
    }

    this.updateReconnectHistory();
  }

  // 渲染延迟图表
  updateLatencyChart() {
    const canvas = document.getElementById('latencyCanvas');
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const width = canvas.width;
    const height = canvas.height;

    // 清空画布
    ctx.clearRect(0, 0, width, height);

    // 获取最近50个数据点
    const data = this.metrics.latencyHistory.slice(-50);
    if (data.length < 2) return;

    // 计算缩放
    const maxLatency = Math.max(...data.map(d => d.latency), 100);
    const stepX = width / (data.length - 1);

    // 绘制线条
    ctx.beginPath();
    ctx.strokeStyle = '#409eff';
    ctx.lineWidth = 2;

    data.forEach((point, index) => {
      const x = index * stepX;
      const y = height - (point.latency / maxLatency) * height;

      if (index === 0) {
        ctx.moveTo(x, y);
      } else {
        ctx.lineTo(x, y);
      }
    });

    ctx.stroke();

    // 绘制当前值
    const lastPoint = data[data.length - 1];
    const lastY = height - (lastPoint.latency / maxLatency) * height;

    ctx.fillStyle = '#67c23a';
    ctx.beginPath();
    ctx.arc(width - 5, lastY, 4, 0, Math.PI * 2);
    ctx.fill();
  }

  startDurationTimer() {
    this.durationTimer = setInterval(() => {
      const now = Date.now();
      const duration = Math.floor((now - this.metrics.connectTime) / 1000);

      const minutes = Math.floor(duration / 60);
      const seconds = duration % 60;

      document.getElementById('wsDuration').textContent = 
        `${minutes}:${seconds.toString().padStart(2, '0')}`;
    }, 1000);
  }

  stopDurationTimer() {
    if (this.durationTimer) {
      clearInterval(this.durationTimer);
    }
  }

  updateLatencyDisplay(latency) {
    const element = document.getElementById('wsLatency');
    if (element) {
      element.textContent = `${latency}ms`;

      // 根据延迟设置颜色
      if (latency < 100) {
        element.style.color = '#67c23a'; // 绿色
      } else if (latency < 300) {
        element.style.color = '#e6a23c'; // 橙色
      } else {
        element.style.color = '#f56c6c'; // 红色
      }
    }
  }

  updateMessageCount() {
    const sent = document.getElementById('wsMessagesSent');
    const received = document.getElementById('wsMessagesReceived');

    if (sent) sent.textContent = this.metrics.messagesSent;
    if (received) received.textContent = this.metrics.messagesReceived;
  }

  updateReconnectHistory() {
    const container = document.getElementById('reconnectHistory');
    if (!container) return;

    container.innerHTML = this.metrics.reconnects.map(event => `
      <div class="history-item ${event.status}">
        <span class="history-time">${event.timestamp}</span>
        <span class="history-status">${this.getStatusText(event.status)}</span>
        ${event.message ? `<span class="history-message">${event.message}</span>` : ''}
      </div>
    `).join('');
  }

  getStatusText(status) {
    const map = {
      'connected': '已连接',
      'disconnected': '断开连接',
      'error': '连接错误'
    };
    return map[status] || status;
  }
}
```

