### 阶段2: Dashboard启动集成 (2小时)

**任务**: 修改 `src/auto-iteration.ts`,集成Dashboard服务

```typescript
// src/auto-iteration.ts

import { createServer } from './dashboard/server';

let dashboardServer: any = null;

export class AutoIterationEngine {
  private config: IterationConfig;

  constructor(config: IterationConfig) {
    this.config = config;
  }

  async start() {
    // 1. 启动Dashboard (如果启用)
    if (this.config.enableDashboard) {
      console.log('🚀 启动 Dashboard...');
      dashboardServer = await createServer();
      await dashboardServer.listen({
        port: 3000,
        host: '0.0.0.0'
      });
      console.log('✅ Dashboard 已启动: http://localhost:3000');
    }

    // 2. 开始迭代循环
    await this.runIterationLoop();
  }

  private async runIterationLoop() {
    while (this.shouldContinue()) {
      // 3. 执行产品经理分析
      const requirement = await this.runProductManager();

      // 4. 推送到Dashboard
      if (dashboardServer && this.config.enableDashboard) {
        await this.pushToDashboard({
          event: 'iteration.started',
          data: { requirement }
        });
      }

      // 5. 执行其他Agent...
    }
  }
}
```

### 阶段3: 实时数据推送 (3小时)

**任务**: 在Agent执行过程中推送状态更新

```typescript
// src/base-agent.ts

import { getDashboardServices } from '../dashboard/server';

export abstract class BaseAgent {
  protected async notifyProgress(phase: string, progress: number) {
    // 发送进度到Dashboard
    const { realtimeService } = getDashboardServices();

    if (realtimeService) {
      realtimeService.broadcast({
        event: 'agent.progress',
        data: {
          agentName: this.agentName,
          phase,
          progress,
          timestamp: new Date().toISOString()
        }
      });
    }
  }

  protected async notifyComplete(result: any) {
    const { realtimeService } = getDashboardServices();

    if (realtimeService) {
      realtimeService.broadcast({
        event: 'agent.completed',
        data: {
          agentName: this.agentName,
          result,
          timestamp: new Date().toISOString()
        }
      });
    }
  }
}
```

